"use client";

import * as React from "react";
import {
  PageHeader,
  Container,
  VStack,
  HStack,
  Cluster,
  Grid,
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  CardFooter,
  SafetyBanner,
  Alert,
  AlertTitle,
  AlertDescription,
  MetadataList,
  Badge,
  Button,
  List,
  ListItem,
  CheckList,
  Checkbox,
  Separator,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  DataTable,
  PersonCell,
  SignedRecord,
  CoSign,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  EmptyState,
  Skeleton,
  Icon,
  type ColumnDef,
  type SignedRecordValue,
  type CoSignValue,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconTemperatureSun,
  IconTruck,
  IconBarrierBlock,
  IconPrinter,
  IconClipboardList,
  IconCrane,
  IconChecklist,
  IconShieldCheck,
  IconClipboardCheck,
  IconCloudRain,
  IconWind,
} from "@tabler/icons-react";

/* ------------------------------------------------------------------ *
 * ドメインデータ（実データ感のあるサンプル）
 * ------------------------------------------------------------------ */

type Severity = "high" | "mid" | "low";

const SEVERITY_META: Record<
  Severity,
  { label: string; variant: "destructive" | "warning" | "secondary" }
> = {
  high: { label: "危険度 高", variant: "destructive" },
  mid: { label: "危険度 中", variant: "warning" },
  low: { label: "危険度 低", variant: "secondary" },
};

interface KyTask {
  id: string;
  name: string;
  company: string;
  severity: Severity;
  hazards: string[];
  measures: string[];
  icon: React.ReactNode;
}

const KY_TASKS: KyTask[] = [
  {
    id: "ky-excavation",
    name: "根切り・山留め掘削（南面）",
    company: "大和土工 5名",
    severity: "high",
    icon: <IconClipboardList size={18} aria-hidden />,
    hazards: [
      "掘削法面の崩壊・土砂の落下",
      "バックホウ後進時の接触・巻き込まれ",
      "埋設物（既設ガス管）の損傷",
    ],
    measures: [
      "土留め支保工を先行、法面勾配を1:0.5以上で管理",
      "重機周囲5mを立入禁止、誘導員を専任配置",
      "試掘済みライン以外は手掘りで確認",
    ],
  },
  {
    id: "ky-crane",
    name: "タワークレーン揚重（鉄筋・型枠）",
    company: "群青重機 3名",
    severity: "high",
    icon: <IconCrane size={18} aria-hidden />,
    hazards: [
      "吊り荷の落下・振れによる激突",
      "旋回範囲内への第三者立入",
      "玉掛けワイヤの外れ",
    ],
    measures: [
      "旋回範囲内は全面立入禁止（バリケード＋監視員）",
      "無線での合図者を1名に限定、相番を明確化",
      "玉掛け前に用具の始業前点検を実施",
    ],
  },
  {
    id: "ky-scaffold",
    name: "外部足場 組立（4〜6F）",
    company: "青葉仮設 4名",
    severity: "high",
    icon: <IconShieldCheck size={18} aria-hidden />,
    hazards: ["高所からの墜落・転落", "資材・工具の落下", "強風時の足場の煽られ"],
    measures: [
      "フルハーネス2丁掛け、親綱を先行設置",
      "工具は落下防止コード、下部を立入禁止",
      "10分平均風速10m/s以上で作業中止",
    ],
  },
  {
    id: "ky-rebar",
    name: "基礎配筋（東区画）",
    company: "鉄和工業 6名",
    severity: "mid",
    icon: <IconChecklist size={18} aria-hidden />,
    hazards: ["鉄筋端部での眼・手の受傷", "運搬時の腰痛・つまずき", "結束線の飛散"],
    measures: [
      "鉄筋端部にキャップ、保護メガネ着用",
      "2人以上での運搬、通路を確保",
      "結束作業は保護手袋を着用",
    ],
  },
  {
    id: "ky-cleanup",
    name: "場内片付け・清掃",
    company: "全社共通",
    severity: "low",
    icon: <IconClipboardCheck size={18} aria-hidden />,
    hazards: ["釘・突起物の踏み抜き", "分別不良による転倒"],
    measures: ["踏み抜き防止インソール着用", "通路と資材置場を明確に区分"],
  },
];

type AttendState = "present" | "late" | "absent";

interface Worker {
  id: string;
  name: string;
  role: string;
  company: string;
  attend: AttendState;
}

const WORKERS: Worker[] = [
  { id: "w1", name: "田中 誠", role: "職長（元請）", company: "群青建設", attend: "present" },
  { id: "w2", name: "佐藤 健一", role: "オペレーター", company: "群青重機", attend: "present" },
  { id: "w3", name: "鈴木 大輔", role: "土工", company: "大和土工", attend: "present" },
  { id: "w4", name: "高橋 涼", role: "とび工", company: "青葉仮設", attend: "present" },
  { id: "w5", name: "渡辺 亮", role: "鉄筋工", company: "鉄和工業", attend: "late" },
  { id: "w6", name: "山本 修", role: "土工", company: "大和土工", attend: "absent" },
];

const ATTEND_META: Record<
  AttendState,
  { label: string; variant: "success" | "warning" | "outline" }
> = {
  present: { label: "出席", variant: "success" },
  late: { label: "遅参", variant: "warning" },
  absent: { label: "欠席", variant: "outline" },
};

interface RosterCheck {
  health: boolean;
  alcohol: boolean;
  ppe: boolean;
  confirm: boolean;
}

const EMPTY_CHECK: RosterCheck = { health: false, alcohol: false, ppe: false, confirm: false };

interface HistoryEntry {
  id: string;
  date: string;
  weather: string;
  headcount: number;
  topHazard: string;
  signedBy: string;
}

const HISTORY: HistoryEntry[] = [
  {
    id: "h-0716",
    date: "2026/07/16（水）",
    weather: "曇り",
    headcount: 18,
    topHazard: "タワークレーン揚重／墜落",
    signedBy: "田中 誠",
  },
  {
    id: "h-0715",
    date: "2026/07/15（火）",
    weather: "雨のち曇り",
    headcount: 15,
    topHazard: "掘削法面の崩壊",
    signedBy: "田中 誠",
  },
  {
    id: "h-0714",
    date: "2026/07/14（月）",
    weather: "晴れ",
    headcount: 20,
    topHazard: "外部足場組立／墜落",
    signedBy: "田中 誠",
  },
];

/* ------------------------------------------------------------------ *
 * KY作業カード（危険 → 対策 → 実施の確認）
 * ------------------------------------------------------------------ */

function KyTaskCard({
  task,
  confirmed,
  onConfirmChange,
}: {
  task: KyTask;
  confirmed: boolean;
  onConfirmChange: (checked: boolean) => void;
}) {
  const sev = SEVERITY_META[task.severity];
  const titleId = `${task.id}-title`;
  return (
    <Card aria-labelledby={titleId}>
      <CardHeader>
        <HStack justify="between" align="start" gap="sm" wrap>
          <HStack gap="sm" align="center">
            {task.icon}
            <div>
              <CardTitle as="h4" id={titleId}>
                {task.name}
              </CardTitle>
              <CardDescription>担当：{task.company}</CardDescription>
            </div>
          </HStack>
          <Badge variant={sev.variant} icon={<IconAlertTriangle size={14} />}>
            {sev.label}
          </Badge>
        </HStack>
      </CardHeader>
      <CardContent>
        <Grid cols={{ base: 1, md: 2 }} gap={4}>
          <section aria-label={`${task.name} の予測される危険`}>
            <p className="mb-1 text-sm font-semibold text-[var(--color-destructive)]">
              予測される危険
            </p>
            <List variant="unordered" spacing="tight">
              {task.hazards.map((h, i) => (
                <ListItem key={i}>{h}</ListItem>
              ))}
            </List>
          </section>
          <section aria-label={`${task.name} の対策`}>
            <p className="mb-1 text-sm font-semibold text-[var(--color-success)]">対策</p>
            <List variant="unordered" spacing="tight">
              {task.measures.map((m, i) => (
                <ListItem key={i}>{m}</ListItem>
              ))}
            </List>
          </section>
        </Grid>
      </CardContent>
      <CardFooter>
        <CheckList
          className="w-full"
          items={[
            {
              id: `${task.id}-confirm`,
              label: "対策を全員へ周知し、実施を確認した",
              description: "職長が現地で対策の実施状況を確認",
              checked: confirmed,
              trailing: (
                <Badge variant={confirmed ? "success" : "outline"}>
                  {confirmed ? "確認済" : "未確認"}
                </Badge>
              ),
            },
          ]}
          onCheckedChange={(_id, checked) => onConfirmChange(checked)}
        />
      </CardFooter>
    </Card>
  );
}

/* ------------------------------------------------------------------ *
 * ページ本体
 * ------------------------------------------------------------------ */

const FOREMAN_ID = "tanaka-makoto";

export default function SafetyKyBoardPage() {
  // KY 作業ごとの実施確認
  const [kyConfirmed, setKyConfirmed] = React.useState<Record<string, boolean>>({});
  // 名簿の各種チェック
  const [roster, setRoster] = React.useState<Record<string, RosterCheck>>({});
  // 最重要指示の確認
  const [safetyAck, setSafetyAck] = React.useState(false);
  // KY記録（ドラフト → 確定でロック、以後は追記のみ）
  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  });
  // 元請責任者による2人承認
  const [cosign, setCosign] = React.useState<CoSignValue | undefined>(undefined);
  // 履歴タブの表示状態（読み込み中 / 空 / 表示）
  const [historyView, setHistoryView] = React.useState<"loaded" | "loading" | "empty">(
    "loaded",
  );

  const getCheck = (id: string): RosterCheck => roster[id] ?? EMPTY_CHECK;

  const setCheck = (id: string, key: keyof RosterCheck, value: boolean) =>
    setRoster((prev) => ({
      ...prev,
      [id]: { ...(prev[id] ?? EMPTY_CHECK), [key]: value },
    }));

  const presentWorkers = WORKERS.filter((w) => w.attend !== "absent");

  const allTasksConfirmed = KY_TASKS.every((t) => kyConfirmed[t.id]);
  const allRosterConfirmed = presentWorkers.every((w) => {
    const c = getCheck(w.id);
    return c.health && c.alcohol && c.ppe && c.confirm;
  });
  const confirmedTaskCount = KY_TASKS.filter((t) => kyConfirmed[t.id]).length;
  const confirmedWorkerCount = presentWorkers.filter((w) => {
    const c = getCheck(w.id);
    return c.health && c.alcohol && c.ppe && c.confirm;
  }).length;

  const canSign = safetyAck && allTasksConfirmed && allRosterConfirmed;
  const cannotSignReason = !safetyAck
    ? "最重要指示の確認が未完了です。"
    : !allTasksConfirmed
      ? "未確認のKY作業があります。"
      : !allRosterConfirmed
        ? "出席者の確認が未完了です。"
        : undefined;

  /* 名簿：デスクトップはテーブル列、モバイルはカードで確認チェック */
  const rosterColumns: ColumnDef<Worker>[] = [
    {
      accessorKey: "name",
      header: "作業員",
      cell: ({ row }) => {
        const w = row.original;
        return <PersonCell name={w.name} secondary={w.role} tertiary={w.company} size="sm" />;
      },
    },
    {
      id: "attend",
      header: "出欠",
      cell: ({ row }) => {
        const m = ATTEND_META[row.original.attend];
        return <Badge variant={m.variant}>{m.label}</Badge>;
      },
    },
    {
      id: "health",
      header: "体調",
      cell: ({ row }) => {
        const w = row.original;
        const disabled = w.attend === "absent";
        return (
          <Checkbox
            checked={getCheck(w.id).health}
            disabled={disabled}
            onCheckedChange={(c) => setCheck(w.id, "health", c)}
            aria-label={`${w.name} の体調確認`}
          />
        );
      },
    },
    {
      id: "alcohol",
      header: "アルコール",
      cell: ({ row }) => {
        const w = row.original;
        const disabled = w.attend === "absent";
        return (
          <Checkbox
            checked={getCheck(w.id).alcohol}
            disabled={disabled}
            onCheckedChange={(c) => setCheck(w.id, "alcohol", c)}
            aria-label={`${w.name} のアルコールチェック（0.00mg）`}
          />
        );
      },
    },
    {
      id: "ppe",
      header: "保護具",
      cell: ({ row }) => {
        const w = row.original;
        const disabled = w.attend === "absent";
        return (
          <Checkbox
            checked={getCheck(w.id).ppe}
            disabled={disabled}
            onCheckedChange={(c) => setCheck(w.id, "ppe", c)}
            aria-label={`${w.name} の保護具確認（ヘルメット・安全帯）`}
          />
        );
      },
    },
    {
      id: "confirm",
      header: "本人確認",
      cell: ({ row }) => {
        const w = row.original;
        const disabled = w.attend === "absent";
        return (
          <Checkbox
            checked={getCheck(w.id).confirm}
            disabled={disabled}
            onCheckedChange={(c) => setCheck(w.id, "confirm", c)}
            aria-label={`${w.name} 本人による確認サイン`}
          />
        );
      },
    },
  ];

  const renderRosterCard = (w: Worker) => {
    const c = getCheck(w.id);
    const disabled = w.attend === "absent";
    const m = ATTEND_META[w.attend];
    return (
      <VStack gap="sm">
        <HStack justify="between" align="center">
          <PersonCell name={w.name} secondary={w.role} tertiary={w.company} size="sm" />
          <Badge variant={m.variant}>{m.label}</Badge>
        </HStack>
        <CheckList
          items={[
            {
              id: `${w.id}-health`,
              label: "体調 良好",
              checked: c.health,
              disabled,
              disabledReason: disabled ? "欠席のため対象外" : undefined,
            },
            {
              id: `${w.id}-alcohol`,
              label: "アルコール 0.00mg",
              checked: c.alcohol,
              disabled,
            },
            {
              id: `${w.id}-ppe`,
              label: "保護具（ヘルメット・安全帯）",
              checked: c.ppe,
              disabled,
            },
            {
              id: `${w.id}-confirm`,
              label: "本人による確認",
              checked: c.confirm,
              disabled,
            },
          ]}
          onCheckedChange={(id, checked) => {
            const key = id.replace(`${w.id}-`, "") as keyof RosterCheck;
            setCheck(w.id, key, checked);
          }}
        />
      </VStack>
    );
  };

  return (
    <>
      <PageHeader
        title="安全KY・朝礼ボード"
        subtitle="（仮称）神谷町第2ビル 新築工事 ／ 2026年7月17日（金）"
        actions={
          <Cluster gap="xs">
            <Button variant="outline" size="sm">
              <IconPrinter size={16} aria-hidden />
              印刷
            </Button>
            <Button variant="outline" size="sm">
              前日をコピー
            </Button>
          </Cluster>
        }
      />

      <Container size="lg" className="py-6">
        <VStack gap={6} align="stretch">
          {/* 最重要の安全指示（確認必須） */}
          <SafetyBanner
            tone="destructive"
            title="タワークレーン旋回範囲内は全面立入禁止"
            titleAs="h2"
            requireAck
            onAcknowledge={() => setSafetyAck(true)}
            ackLabel="内容を確認しました"
            actions={
              <Button variant="outline" size="sm">
                詳細図を見る
              </Button>
            }
          >
            本日13:00〜15:00は南面での鉄筋揚重を実施します。バリケード内・旋回範囲内への立入を禁止。
            監視員（佐藤）の指示に従ってください。
          </SafetyBanner>

          {/* 現場情報 */}
          <Card aria-labelledby="site-info-title">
            <CardHeader>
              <CardTitle as="h2" id="site-info-title">
                現場情報
              </CardTitle>
            </CardHeader>
            <CardContent>
              <MetadataList
                layout="horizontal"
                items={[
                  { label: "現場名", value: "（仮称）神谷町第2ビル 新築工事" },
                  { label: "工期", value: "2026/04/01 〜 2027/03/31" },
                  {
                    label: "本日の天候",
                    value: "晴れのち曇り",
                    icon: <IconCloudRain size={16} aria-hidden />,
                  },
                  {
                    label: "最高気温 / WBGT",
                    value: "34℃ / 28（厳重警戒）",
                    icon: <IconTemperatureSun size={16} aria-hidden />,
                  },
                  { label: "職長", value: "田中 誠（群青建設）" },
                  { label: "本日の参加予定", value: "6社 18名" },
                ]}
              />
            </CardContent>
          </Card>

          <Tabs defaultValue="today">
            <TabsList aria-label="朝礼ボードの表示切替">
              <TabsTrigger value="today">本日の朝礼</TabsTrigger>
              <TabsTrigger value="history">過去の履歴</TabsTrigger>
            </TabsList>

            {/* ---------------- 本日の朝礼 ---------------- */}
            <TabsContent value="today">
              <VStack gap={6} align="stretch" className="pt-4">
                {/* 当日の安全指示・周知事項 */}
                <Card aria-labelledby="notices-title">
                  <CardHeader>
                    <CardTitle as="h2" id="notices-title">
                      当日の安全指示・周知事項
                    </CardTitle>
                    <CardDescription>現場全体への注意喚起</CardDescription>
                  </CardHeader>
                  <CardContent>
                    <VStack gap={3} align="stretch">
                      <Alert
                        variant="warning"
                        icon={<IconTemperatureSun size={18} />}
                        title="熱中症予防（WBGT 28・厳重警戒）"
                      >
                        <AlertDescription>
                          10:00・14:00に全体休憩を追加。塩分・水分をこまめに補給。体調不良は無理せず職長へ申告。
                        </AlertDescription>
                      </Alert>
                      <Alert
                        variant="info"
                        icon={<IconTruck size={18} />}
                        title="重機動線・生コン打設"
                      >
                        <AlertDescription>
                          13:00より生コン車が北ゲートより進入。歩行者動線は西通路へ迂回。誘導員の合図に従うこと。
                        </AlertDescription>
                      </Alert>
                      <Alert
                        variant="destructive"
                        icon={<IconBarrierBlock size={18} />}
                        title="立入禁止区域"
                      >
                        <AlertDescription>
                          南面クレーン旋回範囲／掘削エリア法肩から2m以内は関係者以外立入禁止。
                        </AlertDescription>
                      </Alert>
                      <Alert
                        variant="warning"
                        icon={<IconWind size={18} />}
                        title="強風時の中止基準"
                      >
                        <AlertDescription>
                          10分平均風速10m/s以上、または瞬間15m/s以上で高所・揚重作業を中止。
                        </AlertDescription>
                      </Alert>
                    </VStack>
                  </CardContent>
                </Card>

                {/* 本日の作業と危険予知（KY） */}
                <Card aria-labelledby="ky-title">
                  <CardHeader>
                    <HStack justify="between" align="center" wrap gap="sm">
                      <div>
                        <CardTitle as="h2" id="ky-title">
                          本日の作業と危険予知（KY）
                        </CardTitle>
                        <CardDescription>
                          作業ごとに危険・対策・実施の確認を行う
                        </CardDescription>
                      </div>
                      <Badge variant={allTasksConfirmed ? "success" : "warning"}>
                        確認 {confirmedTaskCount}/{KY_TASKS.length}
                      </Badge>
                    </HStack>
                  </CardHeader>
                  <CardContent>
                    <VStack gap={4} align="stretch">
                      {KY_TASKS.map((task) => (
                        <KyTaskCard
                          key={task.id}
                          task={task}
                          confirmed={!!kyConfirmed[task.id]}
                          onConfirmChange={(checked) =>
                            setKyConfirmed((prev) => ({ ...prev, [task.id]: checked }))
                          }
                        />
                      ))}
                    </VStack>
                  </CardContent>
                </Card>

                {/* 参加者の出欠と確認 */}
                <Card aria-labelledby="roster-title">
                  <CardHeader>
                    <HStack justify="between" align="center" wrap gap="sm">
                      <div>
                        <CardTitle as="h2" id="roster-title">
                          参加者の出欠と確認
                        </CardTitle>
                        <CardDescription>
                          体調・アルコール・保護具・本人確認
                        </CardDescription>
                      </div>
                      <Badge variant={allRosterConfirmed ? "success" : "warning"}>
                        確認済 {confirmedWorkerCount}/{presentWorkers.length}名
                      </Badge>
                    </HStack>
                  </CardHeader>
                  <CardContent>
                    <DataTable<Worker, unknown>
                      columns={rosterColumns}
                      data={WORKERS}
                      filter={null}
                      pageSize={25}
                      hidePaginationSummary
                      renderCard={renderRosterCard}
                      aria-labelledby="roster-title"
                      getRowState={(w) => (w.attend === "absent" ? "absent" : undefined)}
                    />
                  </CardContent>
                </Card>

                {/* KY記録の確定 */}
                <Card aria-labelledby="sign-title">
                  <CardHeader>
                    <CardTitle as="h2" id="sign-title">
                      KY記録の確定
                    </CardTitle>
                    <CardDescription>
                      職長が記録を確定（署名）し、確定後は追記のみ可能。元請責任者が2人承認する。
                    </CardDescription>
                  </CardHeader>
                  <CardContent>
                    <VStack gap={4} align="stretch">
                      <SignedRecord
                        value={record}
                        onChange={setRecord}
                        signerId={FOREMAN_ID}
                        canSign={canSign}
                        cannotSignReason={cannotSignReason}
                        timeFormat={{ dateStyle: "short", timeStyle: "short" }}
                        labels={{
                          draft: "下書き",
                          signed: "確定済",
                          sign: "職長として記録を確定",
                          locked: "確定済み（追記のみ可能）",
                          addendaTitle: "追記記録",
                          addendum: "追記を追加",
                          signedByLabel: "確定者",
                        }}
                      >
                        {({ readOnly }) => (
                          <VStack gap="sm" align="stretch">
                            <p className="text-sm text-[var(--color-muted-foreground)]">
                              本日のKY {KY_TASKS.length}件、参加 {presentWorkers.length}名の
                              危険予知・対策の周知および出欠・体調確認を実施しました。
                            </p>
                            <MetadataList
                              layout="horizontal"
                              items={[
                                { label: "KY確認", value: `${confirmedTaskCount}/${KY_TASKS.length}件` },
                                {
                                  label: "出席者確認",
                                  value: `${confirmedWorkerCount}/${presentWorkers.length}名`,
                                },
                                {
                                  label: "最重要指示",
                                  value: safetyAck ? "確認済" : "未確認",
                                },
                              ]}
                            />
                            {readOnly ? (
                              <Alert variant="success" title="この記録は確定されています">
                                <AlertDescription>
                                  内容の修正はできません。変更が必要な場合は追記で対応してください。
                                </AlertDescription>
                              </Alert>
                            ) : null}
                          </VStack>
                        )}
                      </SignedRecord>

                      <Separator />

                      <div>
                        <h3 className="mb-2 text-sm font-semibold">元請責任者による承認（2人確認）</h3>
                        <CoSign
                          primaryId={FOREMAN_ID}
                          value={cosign}
                          onSign={setCosign}
                          requireReason={false}
                          signerLabel="元請責任者ID（職長と別人）"
                          attestations={[
                            { id: "att-ky", label: "KYの内容と対策が妥当であることを確認した" },
                            { id: "att-roster", label: "全参加者の出欠・体調確認を確認した" },
                          ]}
                          labels={{
                            sign: "承認する",
                            signed: "承認済",
                            pending: "承認待ち",
                          }}
                        />
                      </div>
                    </VStack>
                  </CardContent>
                </Card>
              </VStack>
            </TabsContent>

            {/* ---------------- 過去の履歴 ---------------- */}
            <TabsContent value="history">
              <VStack gap={4} align="stretch" className="pt-4">
                <Card aria-labelledby="history-title">
                  <CardHeader>
                    <HStack justify="between" align="center" wrap gap="sm">
                      <CardTitle as="h2" id="history-title">
                        過去のKY・朝礼の履歴
                      </CardTitle>
                      <Cluster gap="xs" role="group" aria-label="履歴の表示状態（デモ）">
                        <Button
                          size="sm"
                          variant={historyView === "loaded" ? "default" : "outline"}
                          onClick={() => setHistoryView("loaded")}
                        >
                          表示
                        </Button>
                        <Button
                          size="sm"
                          variant={historyView === "loading" ? "default" : "outline"}
                          onClick={() => setHistoryView("loading")}
                        >
                          読み込み中
                        </Button>
                        <Button
                          size="sm"
                          variant={historyView === "empty" ? "default" : "outline"}
                          onClick={() => setHistoryView("empty")}
                        >
                          空
                        </Button>
                      </Cluster>
                    </HStack>
                  </CardHeader>
                  <CardContent>
                    {historyView === "loading" ? (
                      <VStack gap={3} align="stretch" aria-busy="true" aria-live="polite">
                        {[0, 1, 2].map((i) => (
                          <HStack key={i} gap="sm" align="center">
                            <Skeleton shape="circle" className="h-8 w-8 shrink-0" />
                            <VStack gap="xs" className="w-full">
                              <Skeleton shape="text" className="h-4 w-1/3" />
                              <Skeleton shape="text" className="h-3 w-2/3" />
                            </VStack>
                          </HStack>
                        ))}
                      </VStack>
                    ) : historyView === "empty" ? (
                      <EmptyState
                        icon={<Icon icon={IconClipboardList} size="lg" decorative />}
                        title="記録がありません"
                        description="この期間に確定されたKY・朝礼記録はまだありません。"
                        headingLevel={3}
                        action={<Button size="sm">本日の朝礼を開始</Button>}
                      />
                    ) : (
                      <Timeline>
                        {HISTORY.map((h, i) => (
                          <TimelineItem
                            key={h.id}
                            variant="success"
                            connector={i < HISTORY.length - 1}
                          >
                            <TimelineTitle>
                              <HStack gap="sm" align="center" wrap>
                                <span>{h.date}</span>
                                <Badge variant="secondary">{h.weather}</Badge>
                                <Badge variant="success">確定済</Badge>
                              </HStack>
                            </TimelineTitle>
                            <TimelineDescription as="div">
                              <MetadataList
                                layout="horizontal"
                                items={[
                                  { label: "参加", value: `${h.headcount}名` },
                                  { label: "主なKY", value: h.topHazard },
                                  { label: "確定者", value: h.signedBy },
                                ]}
                              />
                            </TimelineDescription>
                            <TimelineTime>{h.date}</TimelineTime>
                          </TimelineItem>
                        ))}
                      </Timeline>
                    )}
                  </CardContent>
                </Card>
              </VStack>
            </TabsContent>
          </Tabs>
        </VStack>
      </Container>
    </>
  );
}
